  const index = DISPATCHED_DIRECTIVES.findIndex(d => d.id === directiveId);
  if (index !== -1) {
    DISPATCHED_DIRECTIVES[index] = {
      ...DISPATCHED_DIRECTIVES[index],
      status: newStatus,
      processedAt: new Date().toISOString(),
      processedByUserId: userId,
    };
  }
};

