// --- START: NEW COMPONENT FOR DIRECTIVES ---
export const AccountantDirectivesView: React.FC<{ user: User }> = ({ user }) => {
  const [directives, setDirectives] = useState<DirectiveSnapshot[]>([]);
  const [loading, setLoading] = useState(true);
  const [processingId, setProcessingId] = useState<string | null>(null);

  const fetchData = async () => {
    setLoading(true);

    // 1. Fetch from Service (Standard Flow)
    const serviceData = await getDispatchedDirectives();

    // 2. Fetch from LocalStorage (Management Archive Bridge)
    const lsDataString = localStorage.getItem('mgmt_archive_history');
    let lsDirectives: DirectiveSnapshot[] = [];

    if (lsDataString) {
        try {
            const history = JSON.parse(lsDataString);
            lsDirectives = history
                .filter((item: any) => item.status === 'SENT')
                .map((item: any) => {
                    const isProcessed = localStorage.getItem(`accounting_task_complete_${item.id}`) === 'true';
                    return {
                        id: `dir_ls_${item.id}`,
                        weekNumber: 0,
                        periodStart: item.date,
                        periodEnd: item.date,
                        dispatchedByUserId: 'u_fin',
                        dispatchedByName: 'Fin Director',
                        dispatchedAt: new Date(item.id).toISOString(),
                        directivesData: item.data.map((d: any) => ({
                            fundName: d.name,
                            category: d.category,
                            approvedAmount: d.approved,
                            availableAmount: d.available,
                            distributionPercentage: d.distributionPercentage,
                            calculatedAmount: d.calculated
                        })),
                        status: isProcessed ? 'processed' : 'pending',
                        processedAt: isProcessed ? new Date().toISOString() : undefined
                    };
                });
        } catch (e) { console.error("Error parsing management archive history", e); }
    }

    // 3. Fetch from new dedicated storage (DirectiveSnapshot)
    const storedDirectives = loadDispatchedDirectives();

    // Combine all sources, de-duplicating by ID if necessary (simplified here)
    const combined = [...lsDirectives, ...serviceData, ...storedDirectives].reduce((acc, curr) => {
        if (!acc.find(d => d.id === curr.id)) {
            acc.push(curr);
        }
        return acc;
    }, [] as DirectiveSnapshot[]);

    // Sort by dispatchedAt desc
    combined.sort((a, b) => new Date(b.dispatchedAt).getTime() - new Date(a.dispatchedAt).getTime());

    setDirectives(combined);
    setLoading(false);
  };

  useEffect(() => {
    fetchData();
    const handleStorage = () => fetchData();
    window.addEventListener('storage', handleStorage);
    return () => window.removeEventListener('storage', handleStorage);
  }, []);

  const handleMarkAsProcessed = async (id: string) => {
    if (window.confirm("ნამდვილად გსურთ დირექტივის შესრულებულად მონიშვნა?")) {
        setProcessingId(id);

        // Handle different storage sources
        if (id.startsWith('dir_ls_')) {
            const originalId = id.replace('dir_ls_', '');
            localStorage.setItem(`accounting_task_complete_${originalId}`, 'true');
        } else {
            // Update in mock service
            await updateDirectiveStatus(id, 'processed', user.id);
            // Update in persistent storage
            markDirectiveProcessed(id, user.id);
        }

        window.dispatchEvent(new Event('storage')); // Notify other tabs/components
        await fetchData();

        setProcessingId(null);
    }
  };

  const handlePrint = () => {
    window.print();
  };

  if (loading) return <div className="p-12 text-center text-gray-500">იტვირთება დირექტივები...</div>;

  const renderSectionRows = (title: string, items: any[], bgClass: string) => {
      if (!items || items.length === 0) return null;
      return (
          <React.Fragment>
              <tr className={bgClass}><td colSpan={5} className="px-4 py-3 font-bold text-xs uppercase">{title}</td></tr>
              {items.map((item: any, i: number) => (
                  <tr key={i} className="hover:bg-gray-50 border-b border-gray-100">
                      <td className="px-4 py-3 font-bold text-gray-800">{item.fundName}</td>
                      <td className="px-4 py-3 text-right font-mono text-gray-500">{item.availableAmount ? formatNumber(item.availableAmount) : '-'}</td>
                      <td className="px-4 py-3 text-center font-mono text-gray-400">{item.distributionPercentage ? `${item.distributionPercentage.toFixed(2)}%` : '-'}</td>
                      <td className="px-4 py-3 text-right font-mono text-gray-500">{item.calculatedAmount ? formatNumber(item.calculatedAmount) : '-'}</td>
                      <td className="px-4 py-3 text-right font-mono font-bold text-black bg-yellow-50/30">{formatNumber(item.approvedAmount)}</td>
                  </tr>
              ))}
          </React.Fragment>
      );
  };

  return (
    <div className="space-y-8">
      <div className="flex justify-between items-center border-b border-black pb-4 no-print">
        <h2 className="text-3xl font-extrabold uppercase tracking-tight flex items-center gap-3">
            <FileText size={28}/> მენეჯეტის დირექტივები
        </h2>
        <p className="text-gray-500 font-bold">მხოლოდ წასაკითხი რეჟიმი</p>
      </div>

      {directives.length === 0 ? (
        <div className="text-center p-12 border-2 border-dashed rounded-lg no-print">
          არ არის შემოსული დირექტივები.
        </div>
      ) : (
        <div className="space-y-6">
          {directives.map(directive => {
            const fundsByCat = {
                Direct: directive.directivesData.filter(d => d.category === 'Direct'),
                Marginal: directive.directivesData.filter(d => d.category === 'Marginal'),
                Adjustable: directive.directivesData.filter(d => d.category === 'Adjustable'),
                Special: directive.directivesData.filter(d => d.category === 'Special'),
            };
            const totalApproved = directive.directivesData.reduce((sum, d) => sum + d.approvedAmount, 0);

            return (
            <div key={directive.id} className="border rounded-lg overflow-hidden shadow-sm bg-white">
              <div className={`flex justify-between items-center p-4 border-b ${directive.status === 'processed' ? 'bg-gray-100' : 'bg-blue-50'}`}>
                <div>
                  <h3 className="font-bold text-lg">
                    {directive.weekNumber > 0 ? `კვირა #${directive.weekNumber}` : 'დირექტივა'} ({directive.periodStart} - {directive.periodEnd})
                  </h3>
                  <div className="text-xs text-gray-500">
                    გამოგზავნილია: {directive.dispatchedByName} - {new Date(directive.dispatchedAt).toLocaleString('ka-GE')}
                  </div>
                  {directive.status === 'processed' && (
                     <div className="text-xs text-green-700 font-bold mt-1">
                        შესრულებულია: {directive.processedAt ? new Date(directive.processedAt).toLocaleString('ka-GE') : 'Completed'}
                     </div>
                  )}
                </div>
                <div className="flex items-center gap-2 no-print">
                    <button onClick={handlePrint} className="p-2 text-gray-600 hover:bg-gray-200 rounded"><Printer size={16}/></button>
                  {directive.status === 'pending' ? (
                    <button 
                        onClick={() => handleMarkAsProcessed(directive.id)} 
                        disabled={processingId === directive.id}
                        className="flex items-center gap-2 px-4 py-2 bg-green-600 text-white text-xs font-bold uppercase rounded shadow-sm hover:bg-green-700 disabled:bg-gray-400"
                    >
                        <Check size={16}/> {processingId === directive.id ? 'მუშავდება...' : 'შესრულებულია'}
                    </button>
                  ) : (
                    <div className="flex items-center gap-2 px-4 py-2 bg-green-100 text-green-700 text-xs font-bold uppercase rounded border border-green-200">
                        <CheckCircle2 size={16}/> შესრულებული
                    </div>
                  )}
                </div>
              </div>

              <div className="overflow-x-auto">
                <table className="w-full text-sm whitespace-nowrap text-left">
                  <thead className="bg-gray-100 font-bold text-gray-600 uppercase border-b border-gray-200">
                    <tr>
                      <th className="px-4 py-3">Fund Name</th>
                      <th className="px-4 py-3 text-right">Available</th>
                      <th className="px-4 py-3 text-center">Dist %</th>
                      <th className="px-4 py-3 text-right">Calculated</th>
                      <th className="px-4 py-3 text-right">Approved (₾)</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-gray-100">
                    {renderSectionRows('SECTION A: Direct', fundsByCat.Direct, 'bg-blue-50 text-blue-900')}
                    {renderSectionRows('SECTION B: Marginal', fundsByCat.Marginal, 'bg-purple-50 text-purple-900')}
                    {renderSectionRows('SECTION C: Adjustable', fundsByCat.Adjustable, 'bg-green-50 text-green-900')}
                    {renderSectionRows('SECTION D: Special', fundsByCat.Special, 'bg-red-50 text-red-900')}
                  </tbody>
                  <tfoot className="bg-gray-800 text-white font-bold border-t border-gray-200">
                      <tr>
                          <td colSpan={4} className="px-4 py-3 text-right uppercase text-xs">Total Approved:</td>
                          <td className="px-4 py-3 text-right font-mono text-sm">{formatNumber(totalApproved)}</td>
                      </tr>
                  </tfoot>
                </table>
              </div>
            </div>
          )})}
        </div>
      )}
    </div>
  );
};


