        status: user.role === UserRole.EMPLOYEE ? RequestStatus.WAITING_DEPT_APPROVAL : RequestStatus.COUNCIL_REVIEW,
        createdAt: new Date().toISOString(),
        boardDate: new Date().toISOString().split('T')[0],
