export const updateRequestStatus = async (id: string, status: RequestStatus, userId: string) => {
    const req = REQUESTS.find(r => r.id === id);
    if (req) {
        req.status = status;
        req.updatedAt = new Date().toISOString();
        if (status === RequestStatus.PAID) {
            if (req.assignedFundId) {
                const fb = FUND_BALANCES.find(f => f.id === req.assignedFundId);
                if (fb) {
                    fb.totalSpent += req.totalAmount;
                    fb.remaining -= req.totalAmount;
                }
            }
        }
    }
};
