  const fetchRequests = async () => {
    // Uses DISPATCHED_TO_ACCOUNTING filter + PAID
    const data = await getAccountingRequests();
    setRequests(data);
    setLoading(false);
  };

  useEffect(() => {
    fetchRequests();
  }, []);

  const handlePay = async (requestId: string) => {
    setProcessingId(requestId);
    try {
      // Updates status to PAID
      await updateRequestStatus(requestId, RequestStatus.PAID, user.id);
      await fetchRequests(); 
    } catch (e) {
      console.error(e);
      alert('გადახდის დაფიქსირება ვერ მოხერხდა');
    } finally {
      setProcessingId(null);
    }
