                     </div>
                  )}
                </div>
                <div className="flex items-center gap-2 no-print">
                    <button onClick={handlePrint} className="p-2 text-gray-600 hover:bg-gray-200 rounded" title="ბეჭდვა"><Printer size={16}/></button>
                  {directive.status === 'pending' ? (
                    <button 
