      {/* Test Flow Overlay */}
      {testFlowState.active && (
         <div className="fixed bottom-4 right-4 z-50 bg-black text-white p-4 rounded-lg shadow-2xl border border-gray-700 flex items-center gap-4 animate-in slide-in-from-bottom-5">
