const CurrencyWidget = () => {
  const [rates, setRates] = useState({ USD: 0, EUR: 0 });
  const [inflation, setInflation] = useState(0);

  useEffect(() => {
    const fetchIndicators = async () => {
      setRates(await getCurrencyRates());
      setInflation(await getInflationRate());
