    userId: user.id,
    requesterName: user.name,
    department: user.department,
    managerId: manager?.id || 'u_ceo',
    date: now.toISOString().split('T')[0],
    category: 'Uncategorized',
    itemName: 'N/A',
    quantity: 1,
    unitPrice: 0,
    currency: Currency.GEL,
