    revenuePotential: '',
    priority: Priority.LOW,
    alternativesChecked: false,
    selectedOptionReason: '',
    status: RequestStatus.WAITING_DEPT_APPROVAL,
    createdAt: now.toISOString(),
    boardDate: determineBoardDateForRequest(now, user.role).toISOString(),
