    ];

    let lateEntriesCount = 0;
    const requestsToCreate = [];

    for (let i = 0; i < 50; i++) {
        const deptConfig = departmentsConfig[i % departmentsConfig.length];
        const user = USERS[deptConfig.userKey];

        let weekOffset;
