              ${loading ? 'bg-gray-400 cursor-wait' : 'bg-green-600 hover:bg-green-700 hover:shadow-lg'}
            `}
          >
            <Send size={18} />
            {loading ? 'მუშავდება...' : 'გაგზავნა (ბუღალტერთან)'}
          </button>
        </div>

      </form>
    </div>
  );
};

