    setInvoices(data.filter(inv => inv.creatorId === user.id || user.role === 'FIN_DIRECTOR' || user.role === 'FOUNDER'));
    setLoading(false);
  };

  useEffect(() => {
    fetchInvoices();
  }, [user.id]);

  const handleShowPrintModal = (invoice: Invoice) => {
    setPrintInvoice(invoice);
  };

