      const ceo = USERS['u_ceo'];
      setCurrentUser(ceo);
      setActiveTab('approvals');
      setTestFlowState({ active: true, step: 2, message: 'Logged in as CEO: Reviewing Request' });

      // Wait 4 seconds
      await new Promise(r => setTimeout(r, 4000));

      // Step 4: Login as Fin Director
      setTestFlowState({ active: true, step: 3, message: 'Step 3: Switching to Financial Director...' });
      await new Promise(r => setTimeout(r, 1000));
      const fin = USERS['u_fin'];
      setCurrentUser(fin);
      setActiveTab('approvals');
      setTestFlowState({ active: true, step: 3, message: 'Logged in as Fin. Director: Final Check' });

      // Wait 3 seconds then clear overlay
      await new Promise(r => setTimeout(r, 3000));
      setTestFlowState({ active: false, step: 0, message: '' });
  };

  // If not logged in, show Landing Page
  if (!currentUser) {
    return (
      <LandingPage 
        onSelectRole={handleLogin} 
        language={language} 
        setLanguage={setLanguage} 
        onRunTestFlow={handleRunTestFlow}
      />
    );
  }

  const isAdmin = currentUser.role === UserRole.FOUNDER || currentUser.role === UserRole.FIN_DIRECTOR;
  const isTopLevel = currentUser.role === UserRole.FOUNDER || currentUser.role === UserRole.FIN_DIRECTOR || currentUser.role === UserRole.CEO;
  const isManagerLevel = [UserRole.COMMERCIAL_DIRECTOR, UserRole.TECH_DIRECTOR, UserRole.ADMIN, UserRole.MANAGER, UserRole.PARTS_MANAGER].includes(currentUser.role);
  const isAccountant = currentUser.role === UserRole.ACCOUNTANT;
  const isSubAccountant = currentUser.role === UserRole.SUB_ACCOUNTANT;
  const canViewGlobalArchive = currentUser.role === UserRole.FOUNDER || currentUser.role === UserRole.FIN_DIRECTOR;

  const canViewInventory = [
    UserRole.FOUNDER,
    UserRole.FIN_DIRECTOR,
    UserRole.CEO,
    UserRole.COMMERCIAL_DIRECTOR,
    UserRole.ACCOUNTANT,
    UserRole.SUB_ACCOUNTANT,
    UserRole.PARTS_MANAGER
  ].includes(currentUser.role);

  // PROMPT 6.8-003: Refined role-based access for Revenue Analysis
  const isCommercialDirector = currentUser.role === UserRole.COMMERCIAL_DIRECTOR;
  const isTechDirector = currentUser.role === UserRole.TECH_DIRECTOR;
  const canViewProjects = isTopLevel || isCommercialDirector;
  const canViewServiceAndParts = isTopLevel || isTechDirector;

  return (
    <>
      <Layout 
        user={currentUser} 
        activeTab={activeTab} 
        setActiveTab={setActiveTab}
        onLogout={handleLogout}
        language={language}
        setLanguage={setLanguage}
        isSidebarExpanded={isSidebarExpanded}
      >
        {activeTab === 'dashboard' && (
          <Dashboard user={currentUser} />
        )}

        {/* UPDATED: Route 'approvals' to the new Financial Council Engine */}
        {activeTab === 'approvals' && isTopLevel && (
          <FinancialCouncil user={currentUser} />
        )}

        {/* PROMPT 6.1-008: Revert 'council-share' to a placeholder */}
        {activeTab === 'council-share' && (isTopLevel || isManagerLevel) && (
          <div className="p-12 text-center text-gray-500 border-2 border-dashed border-gray-200 rounded-lg bg-gray-50">
            <h3 className="text-xl font-bold text-black">გაზიარების მოდული</h3>
            <p className="mt-2 text-sm">ეს სექცია განკუთვნილია შიდა ინფორმაციის გასაზიარებლად.</p>
          </div>
        )}

        {/* PROMPT 7.1-002: Implement ManagementView for 'management' tab */}
        {activeTab === 'management' && (
          // FIX: Pass the 'user' prop to the ManagementView component as it is required.
          isTopLevel ? <ManagementView user={currentUser} /> : <AccessDenied />
        )}

        {/* BUDGETING ROUTES (PROMPT 414) */}
        {activeTab === 'prev-year-budget' && (
          isTopLevel ? <Budgeting user={currentUser} year={2025} /> : <AccessDenied />
        )}
        {activeTab === 'curr-year-budget' && (
          isTopLevel ? <Budgeting user={currentUser} year={2026} /> : <AccessDenied />
        )}
        {activeTab === 'budget-analysis' && (
          isTopLevel ? <BudgetAnalysis user={currentUser} /> : <AccessDenied />
        )}

        {/* PROMPT 6.1-008: Corrected Cash Inflow Route */}
        {activeTab === 'cash-inflow' && (isTopLevel || isManagerLevel) && (
          <CashInflowView user={currentUser} />
        )}

        {/* PROMPT 6.7-001 & 6.8-003: Isolated and Role-Restricted Revenue Analysis Modules */}
        {activeTab === 'revenue-projects' && (
          canViewProjects ? <RevenueAnalysis category="პროექტები" /> : <AccessDenied />
        )}
        {activeTab === 'revenue-service' && (
          canViewServiceAndParts ? <RevenueAnalysis category="სერვისი" /> : <AccessDenied />
        )}
        {activeTab === 'revenue-parts' && (
          canViewServiceAndParts ? <RevenueAnalysis category="ნაწილები" /> : <AccessDenied />
        )}

        {activeTab === 'accounting' && isAccountant && (
          <AccountingDashboard user={currentUser} />
        )}
        {activeTab === 'accounting-directives' && isAccountant && (
          <AccountantDirectivesView user={currentUser} />
        )}

        {/* FIX: Render AccountantInvoicesView for the Sub-Accountant role */}
        {activeTab === 'sub-accounting' && isSubAccountant && (
          <div className="animate-in fade-in slide-in-from-bottom-4 duration-500">
            <AccountantInvoicesView user={currentUser} />
          </div>
        )}

        {activeTab === 'inventory-proforma' && (
          canViewInventory ? <ProformaInvoiceForm user={currentUser} /> : <AccessDenied />
        )}

        {activeTab === 'inventory-generated' && (
          canViewInventory ? <GeneratedInvoicesView user={currentUser} /> : <AccessDenied />
        )}

        {activeTab === 'customers' && (isTopLevel || isManagerLevel) && (
          <div className="p-12 text-center text-gray-500 border-2 border-dashed border-gray-200 rounded-lg bg-gray-50 mt-10">
            <h3 className="text-xl font-bold text-black">მომხმარებლები (კლიენტები)</h3>
            <p className="mt-2 text-sm">მოდული დამუშავების პროცესშია. ლოგიკა დაემატება მოგვიანებით.</p>
          </div>
        )}

        {activeTab === 'global-archive' && canViewGlobalArchive && (
          <GlobalArchive user={currentUser} />
        )}

        {activeTab === 'request' && (
          <RequestForm 
            user={currentUser} 
            onSuccess={() => setActiveTab('dashboard')} 
          />
        )}

        {activeTab === 'users' && isAdmin && (
          <UserManagement currentUser={currentUser} language={language} />
        )}

        {activeTab === 'settings' && (
          <div className="max-w-3xl mx-auto space-y-8">
            <div className="text-center p-8 border-b border-gray-100">
              <h2 className="text-2xl font-bold mb-2 text-black">{language === 'EN' ? 'Settings' : 'პარამეტრები'}</h2>
              <div className="mt-4 p-4 bg-gray-50 text-gray-800 rounded border border-gray-200 inline-block text-sm font-medium">
                {language === 'EN' ? 'Current Role:' : 'მიმდინარე როლი:'} <strong>{currentUser.role}</strong>
              </div>
            </div>

            {isAdmin && <GlobalSettings language={language} />}

            {/* Test Center Component - Full Cycle Environment Test */}
            <TestCenter />

            {/* Legacy Data Gen Tools */}
            <div className="bg-white rounded-lg p-6 shadow-sm border border-gray-200">
              <div className="flex items-center gap-3 mb-6 border-b border-gray-100 pb-4">
                <Database className="text-gray-400" size={20} />
                <div>
                  <h3 className="font-bold text-lg text-black">Quick Data Generators</h3>
                  <p className="text-xs text-gray-400">Manual Population</p>
                </div>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <button 
                  onClick={handleGenerateData}
                  disabled={isGenerating}
                  className={`
                    w-full py-3 rounded font-bold uppercase text-xs tracking-wider transition-all flex items-center justify-center gap-3 border
                    ${isGenerating 
                      ? 'bg-gray-100 text-gray-400 cursor-not-allowed' 
                      : 'bg-white text-black border-black hover:bg-black hover:text-white'}
                  `}
                >
                  {isGenerating ? 'Generating...' : 'Generate New Requests'}
                </button>

                <button 
                  onClick={handleGenerateAccountingData}
                  disabled={isGenerating}
                  className={`
                    w-full py-3 rounded font-bold uppercase text-xs tracking-wider transition-all flex items-center justify-center gap-3 border
                    ${isGenerating 
                      ? 'bg-gray-100 text-gray-400 cursor-not-allowed' 
                      : 'bg-white text-black border-black hover:bg-black hover:text-white'}
                  `}
                >
                  {isGenerating ? 'Generating...' : 'Generate Accounting Data'}
                </button>
              </div>

              {genSuccess && (
                  <div className="mt-4 p-3 bg-green-50 border border-green-200 text-green-700 rounded text-sm font-medium flex items-center gap-2 animate-in fade-in slide-in-from-top-2">
                    <CheckCircle size={16} />
                    Data generated successfully.
                  </div>
              )}
            </div>
          </div>
        )}
      </Layout>

      {/* Test Flow Overlay */}
      {testFlowState.active && (
         <div className="fixed bottom-4 right-4 z-50 bg-black text-white p-4 rounded-lg shadow-2xl border border-gray-700 flex items-center gap-4 animate-in slide-in-from-bottom-5">
             <Loader2 className="animate-spin text-yellow-400" size={24} />
             <div>
                <div className="text-xs font-bold text-gray-400 uppercase tracking-wider">Test Automation Running</div>
                <div className="font-bold text-sm">{testFlowState.message}</div>
             </div>
         </div>
      )}
    </>
  );
}

export default App;

payload.text:
ქვემოთ წარმოდგენილია უკიდურესად დეტალური, ყოვლისმომცველი **პროდუქტის მოთხოვნების დოკუმენტი (PRD)**, რომელიც ეფუძნება თქვენს მიერ მოწოდებულ კოდს. ეს დოკუმენტი მზად არის Copy/Paste-ისთვის და იდეალურია დეველოპერული გუნდისთვის (ან AI ასისტენტისთვის) პროექტის უშეცდომოდ ასაწყობად.

---

# 📄 Product Requirements Document (PRD)
**პროექტის დასახელება:** Financial Board - Elevators (FinBoard)
**ვერსია:** 9.6 (სრული არქიტექტურული აღწერა)
**ტიპი:** შიდა კორპორატიული ფინანსური მართვისა და ხარჯების კონტროლის პლატფორმა (ERP/Workflow)

## 1. პროექტის მიზანი და ხედვა
**FinBoard** შექმნილია კომპანიის ფინანსური ნაკადების (შემოსავლები, ხარჯები, ბიუჯეტირება, დავალიანებები, ინვოისირება) ცენტრალიზებული მართვისთვის. სისტემა უზრუნველყოფს გამჭვირვალე, იერარქიულ დადასტურების ჯაჭვს, სადაც თითოეულ ხარჯს აქვს მკაცრად განსაზღვრული სასიცოცხლო ციკლი — დაწყებული რიგითი თანამშრომლის მოთხოვნიდან, დამთავრებული ფინანსური საბჭოს დასტურითა და ბუღალტერიის მიერ გადახდით.

## 2. ტექნოლოგიური სტეკი
*   **Frontend Framework:** React 19 (Vite)
*   **ენა:** TypeScript (მკაცრი ტიპიზაციით)
*   **სტილიზაცია:** Tailwind CSS
*   **UI კომპონენტები / ხატულები:** Lucide React
*   **State Management:** Zustand (Persist მიდლვეარით, მონაცემების LocalStorage-ში შესანახად)
*   **ანალიტიკა / დიაგრამები:** Recharts
*   **ექსპორტი:** XLSX (Excel ფაილების გენერაცია)
*   **ხელოვნური ინტელექტი:** `@google/genai` (Gemini API - შემაჯამებელი რეპორტებისთვის)
*   **ლოკალიზაცია (i18n):** ქართული (GE - ნაგულისხმევი) და ინგლისური (EN).

---

## 3. მომხმარებლების როლები და იერარქია (Access Control)
სისტემაში განსაზღვრულია 11 როლი 4 ძირითად დონეზე:

### დონე 1: Top Level (C-Level / Board)
აქვთ სრული წვდომა ფინანსურ მოდულებზე, ბიუჯეტზე და საბჭოს მართვაზე.
1.  **FOUNDER (დამფუძნებელი):** სუპერ-ადმინისტრატორი. ხედავს ყველაფერს, შეუძლია იუზერების მართვა.
2.  **FIN_DIRECTOR (ფინანსური დირექტორი / CFO):** მართავს ფონდების მატრიცას, ანაწილებს თანხებს, გასცემს ფინანსურ დასტურს მოთხოვნებზე, ხურავს ფინანსურ კვირას და აგზავნის დირექტივებს ბუღალტერიაში.
3.  **CEO (აღმასრულებელი დირექტორი):** ხედავს სრულ სურათს, აქვს დადასტურების უფლება საბჭოს ეტაპზე.

### დონე 2: Management Level (დეპარტამენტის ხელმძღვანელები)
აქვთ უფლება დაადასტურონ (Level 2 Approval) თავიანთი თანამშრომლების მოთხოვნები ან დააბრუნონ უკან. ხედავენ შემოსავლების ანალიზს თავიანთი მიმართულებით.
4.  **COMMERCIAL_DIRECTOR (კომერციული დირექტორი):** წვდომა პროექტების შემოსავლების მოდულზე.
5.  **TECH_DIRECTOR (ტექნიკური დირექტორი):** წვდომა სერვისისა და ნაწილების შემოსავლების მოდულებზე.
6.  **ADMIN (ადმინისტრაციული მენეჯერი):** ოფისის ხარჯების კონტროლი.
7.  **BIZ_DEV & MANAGER:** სხვა საშუალო რგოლის მენეჯერები.
8.  **PARTS_MANAGER (ნაწილების მენეჯერი):** სპეციფიკური როლი — ქმნის პროფორმა ინვოისებს და უგზავნის ბუღალტერს დასაფასებლად.

### დონე 3: Accounting Level (ბუღალტერია)
9.  **ACCOUNTANT (მთავარი ბუღალტერი):** იღებს C-Level-ისგან ფინანსურ დირექტივებს და ასრულებს ხარჯების გადახდას.
10. **SUB_ACCOUNTANT (ბუღალტერი / ასისტენტი):** ევალება პროფორმა ინვოისების მიღება ნაწილების მენეჯერისგან, ფასების დადგენა და რეალური ინვოისის გენერირება.

### დონე 4: Base Level
11. **EMPLOYEE (დასაქმებული):** შეუძლია მხოლოდ Expense Request (ხარჯვის მოთხოვნის) შევსება, გაგზავნა და თავისი სტატუსების კონტროლი Dashboard-ზე.

---

## 4. ძირითადი სამუშაო პროცესები (Workflows)

### 4.1. ხარჯვის მოთხოვნის (Expense Request) სასიცოცხლო ციკლი
ყველა ხარჯი გადის მკაცრ ეტაპებს (სტატუსებს):
1.  **ფორმის შევსება (`WAITING_DEPT_APPROVAL`):** ინიციატორი ავსებს ფორმას (DTSQ მეთოდოლოგიით: დასაბუთება, თანხა, პოტენციალი, ბაზრის მოკვლევა მინ. 3 ვარიანტით).
    *   *წესი:* ფინანსური კვირა სრულდება ყოველ ხუთშაბათს 16:00 საათზე. ამის მერე გაგზავნილი მოთხოვნა ავტომატურად გადადის მომდევნო კვირის საბჭოზე (არ ვრცელდება C-Level-ზე).
2.  **Level 2 დასტური (`COUNCIL_REVIEW`):** უშუალო მენეჯერი (Dashboard-ის INBOX-იდან) ადასტურებს, უარყოფს (`REJECTED`) ან აბრუნებს შესასწორებლად (`RETURNED_TO_SENDER`).
3.  **Level 3 საბჭოს განხილვა (`FD_APPROVED` / `RETURNED_TO_MANAGER`):** ფინანსური დირექტორი და CEO განიხილავენ ფინანსურ საბჭოზე. CFO უთითებს დაფინანსების წყაროს (Fund ID).
4.  **Level 12 ბუღალტერიაში გადაცემა (`DISPATCHED_TO_ACCOUNTING`):** ფინანსური დირექტორი ამტკიცებს საბოლოოდ სრულ სიას და აგზავნის ბუღალტერიაში.
5.  **Level 13 გადახდა (`PAID`):** მთავარი ბუღალტერი საკუთარ კაბინეტში აჭერს "გადახდას". თანხა აკლდება ბიუჯეტის ფაქტიურ ნაშთს.

### 4.2. ინვოისირების ორმხრივი პროცესი (Inventory Workflow)
1.  **ეტაპი 1:** `PARTS_MANAGER` ავსებს "პროფორმა ინვოისს" (კლიენტის დეტალები, პროდუქციის სია, რაოდენობები, სავარაუდო ფასები). სტატუსი: `PENDING_ACCOUNTANT`.
2.  **ეტაპი 2:** `SUB_ACCOUNTANT` ხსნის ინვოისების ტაბს, უთითებს ზუსტ "ერთეულის ფასებს" და აგენერირებს დოკუმენტს. სტატუსი: `GENERATED`.
3.  **ეტაპი 3:** `PARTS_MANAGER` გენერირებული ინვოისების ტაბში ხედავს გამზადებულ დოკუმენტს. შეუძლია დაბეჭდოს/შეინახოს PDF-ში (სპეციალური Print CSS შაბლონით) და კლიენტთან გაგზავნის შემდეგ მიანიჭოს სტატუსი `COMPLETED`.

---

## 5. სისტემის ხედვები და მოდულები (Views & Modules)

### 5.1. Dashboard (მთავარი პანელი)
*   **ყველასთვის:** აქტიური და არქივირებული (თვეების მიხედვით ჩაშლილი) მოთხოვნები სტატუსების ფერადი ბეიჯებით.
*   **მენეჯერებისთვის:** ჩანს INBOX სექცია ხელქვეითების მოთხოვნების დასადასტურებლად.
*   **შესასწორებელი ბლოკი:** თუ მოთხოვნა დაბრუნდა, ჩანს წითელ ბლოკში კომენტარით და ხელახლა გაგზავნის ღილაკით.

### 5.2. Financial Council (ფინანსური საბჭო - 14 ნაბიჯი)
მხოლოდ Top-Level წვდომა.
*   **Step 0: არქივი:** წინა კვირების სესიების ნახვა, წლის და თვის ფილტრებით.
*   **Step 1: ბანკები:** ანგარიშების სინქრონიზაცია და შემოსავლების კატეგორიზაცია.
*   **Step 2: ფონდების მატრიცა:** კვირის ჯამური შემოსავლის გადანაწილება 4 სექციად:
    *   *Section A (Direct):* პროექტების, სერვისის პირდაპირი ხარჯები.
    *   *Section B (Marginal):* ხელფასები, გადასახადები, ფიქსირებული ხარჯები.
    *   *Section C (Adjustable):* ბონუსები, მარკეტინგი (პროცენტული დარიცხვით).
    *   *Section D (Special):* სარეზერვო, დამფუძნებლის ფონდი.
*   **Step 3: დირექტორების დასტური (DirectorApprovals):** შემოსული მოთხოვნების განხილვა, ფონდების მინიჭება მატრიციდან, ხელმოწერები (დასტურდება/ბრუნდება/უარყოფილია).
*   **Step 5: დავალიანებები (DebtManagement):** დებიტორებისა და კრედიტორების ცხრილი (საწყისი ნაშთი, ზრდა, კლება, საბოლოო ნაშთი). აქვს AI ანალიტიკის გრაფიკი.
*   **Step 11 & 12:** საბოლოო რევიზია და ბუღალტერიისთვის პაკეტურად გადაცემა.
*   **Step 13: საბჭოს დახურვა:** რეპორტის გენერაცია. Gemini AI აგენერირებს ტექსტურ დასკვნას ქართულ ენაზე. ფიქსირდება "Snaphot" არქივისთვის.

### 5.3. Management View (მენეჯეტი)
ალტერნატიული მართვის პანელი (C-Level).
*   ტაბები: თავფურცელი, შემოსავლები (აგრეგირებული), ფონდების მოძრაობა, დირექტივები.
*   აქედან ხდება "დირექტივის" გაგზავნა მთავარ ბუღალტერთან, რაც ავტომატურად ბლოკავს ფინანსურ კვირას (Lock).

### 5.4. Accounting Dashboard (მთავარი ბუღალტერი)
*   **დირექტივების ტაბი:** ხედავს C-Level-ის მიერ გამოგზავნილ ფონდების გადანაწილებას და მონიშნავს "შესრულებულად".
*   **მიმდინარე ტაბი:** ეკრანზე ჩანს `DISPATCHED_TO_ACCOUNTING` სტატუსის მქონე ხარჯები. აჭერს "გადახდას", რაც სტატუსს ცვლის `PAID`-ზე.
*   **არქივი / ინვოისები:** გადახდილი ჩანაწერები და (საჭიროების შემთხვევაში) ინვოისების გადამოწმება.

### 5.5. Budgeting & Budget Analysis (ბიუჯეტი)
*   **ბიუჯეტი 2025 / 2026:** წლიური გეგმის ცხრილი, რომელიც ჩაშლილია 12 თვედ.
*   აჩვენებს გეგმას, ფაქტს (Actual), გადახრას თანხაში (Var $) და პროცენტში (Var %).
*   აქვს დაგეგმვის რეჟიმი (Planning Mode) გეგმის შესაცვლელად.
*   **ბიუჯეტის ანალიზი:** 2025 და 2026 წლების პირდაპირი შედარება კომენტარების ველებით.

### 5.6. Revenue Analysis (შემოსავლების ანალიზი)
იყოფა 3 იზოლირებულ მოდულად (პროექტები, სერვისი, ნაწილები).
*   **ფუნქციონალი:** კლიენტი, კონტრაქტის N, ვადა, პროდუქცია, სართულების რაოდენობა, ღირებულება.
*   **გრაფიკი (Tranches):** თანხის მიღების დაგეგმვა თვეებისა და პროცენტების მიხედვით (მაგ: I % - 30% თებერვალში). სულ 100%.
*   **ფასის ანალიზი:** ავტომატური კალკულაცია: ერთეულის ღირებულება, სართულის ღირებულება, კვირისა და თვის ღირებულება.
*   ჩანაწერის შეწყვეტის (Termination) ფუნქცია მიზეზისა და თარიღის მითითებით.

### 5.7. Cash Inflow (ფულადი შემოდინებები)
*   ყოველკვირეული ტრეკერი: კლიენტი, კატეგორია, დაგეგმილი თანხა, ფაქტიური თანხა, კომენტარი.
*   არქივირებისა და AI ანალიტიკის მხარდაჭერა.

### 5.8. Global Archive (გლობალური არქივი)
*   მხოლოდ C-Level-ისთვის.
*   ყველა გადახდილი, უარყოფილი თუ დაბრუნებული მოთხოვნის ერთიანი ბაზა გაფართოებული ფილტრებით (თარიღი, დეპარტამენტი, ძებნა).

---

## 6. UI / UX და სტილისტიკა
*   **ფერთა პალიტრა (მინიმალისტური & კორპორატიული):** თეთრი ფონი, შავი ტექსტი, ნაცრისფერი საზღვრები.
*   **სტატუსის ფერები:**
    *   *მწვანე:* Paid, Completed, პოზიტიური ვარიაცია.
    *   *წითელი:* Rejected, ნეგატიური ვარიაცია (ბიუჯეტის გადახარჯვა).
    *   *ყვითელი/ნარინჯისფერი:* Pending ეტაპები, დასაბრუნებელი ტრანზაქციები.
    *   *ლურჯი/იისფერი:* Top-Level დასტურები (FD Approved).
*   **ნავიგაცია:**
    *   *Desktop:* მარცხენა Sidebar ანიმირებული (Expand/Collapse) მენიუთი, კატეგორიზებული ბლოკებით (ანალიტიკა, შემოსავლები, ბიუჯეტი).
    *   *Mobile:* ზედა Header ენის/გამოსვლის ღილაკით და ქვედა ფიქსირებული App Bar ძირითადი ტაბებისთვის.
*   **ცხრილები:** ყველა ცხრილი უნდა იყოს რესპონსიული (ჰორიზონტალური სქროლით `overflow-x-auto`).
*   **ბეჭდვა (Print):** აქვს სპეციალური Print CSS (`@media print`), რომელიც მალავს მენიუებსა და ღილაკებს და აჩვენებს მხოლოდ A4 ფორმატზე მორგებულ რეპორტებს (მაგ: ინვოისის შაბლონი).

